SELECT

FROM sys_knowledge_doc
WHERE state = '1'
AND userId = #{userId}
AND knowledgeBaseId = #{knowledgeBaseId}
AND docName LIKE CONCAT('%', #{docName}, '%')
AND status = #{status}
AND docType = #{docType}
ORDER BY createTime DESC

